import React from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { 
    Mail, 
    Phone, 
    MapPin, 
    Facebook, 
    Twitter, 
    Instagram, 
    Linkedin, 
    Youtube,
    Heart,
    Sparkles,
    Zap,
    ChevronUp,
    Home,
    Info,
    GraduationCap,
    MessageCircle,
    Newspaper,
    Briefcase
} from 'lucide-react';

const Footer = () => {
    const { t } = useTranslation();

    // Scroll to top function
    const scrollToTop = () => {
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    // Navigation links
    const navigationLinks = [
        { name: t('navigation.home') || 'Home', path: '/', icon: Home },
        { name: t('navigation.about') || 'About', path: '/about', icon: Info },
        { name: t('navigation.programs') || 'Programs', path: '/courses', icon: GraduationCap },
        { name: t('navigation.contact') || 'Contact', path: '/contact', icon: MessageCircle },
        { name: t('navigation.news') || 'News & Events', path: '/news', icon: Newspaper },
        { name: t('navigation.career') || 'Career', path: '/career', icon: Briefcase }
    ];

    // Social links (icons only)
    const socialLinks = [
        { icon: Facebook, url: '#', color: 'hover:text-blue-500 hover:bg-blue-500/10' },
        { icon: Twitter, url: '#', color: 'hover:text-sky-400 hover:bg-sky-400/10' },
        { icon: Instagram, url: '#', color: 'hover:text-pink-500 hover:bg-pink-500/10' },
        { icon: Linkedin, url: '#', color: 'hover:text-blue-600 hover:bg-blue-600/10' },
        { icon: Youtube, url: '#', color: 'hover:text-red-500 hover:bg-red-500/10' }
    ];

    return (
        <footer className="relative bg-gradient-to-br from-slate-900 via-blue-950 to-purple-950 text-white overflow-hidden">
            {/* Animated Background */}
            <div className="absolute inset-0 overflow-hidden">
                {/* Floating Orbs */}
                <div className="absolute top-10 left-10 w-40 h-40 bg-blue-500/10 rounded-full blur-2xl animate-pulse"></div>
                <div className="absolute bottom-10 right-10 w-60 h-60 bg-purple-500/10 rounded-full blur-2xl animate-pulse delay-300"></div>
                <div className="absolute top-1/2 left-1/2 w-32 h-32 bg-pink-500/10 rounded-full blur-2xl animate-pulse delay-700 transform -translate-x-1/2 -translate-y-1/2"></div>

                {/* Grid Pattern */}
                <div className="absolute inset-0 bg-[linear-gradient(rgba(255,255,255,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.02)_1px,transparent_1px)] bg-[size:40px_40px]"></div>

                {/* Floating Particles */}
                {[...Array(12)].map((_, i) => (
                    <div
                        key={i}
                        className="absolute w-1 h-1 bg-white/30 rounded-full animate-pulse"
                        style={{
                            left: `${Math.random() * 100}%`,
                            top: `${Math.random() * 100}%`,
                            animationDelay: `${Math.random() * 3}s`,
                            animationDuration: `${2 + Math.random() * 3}s`
                        }}
                    ></div>
                ))}
            </div>

            {/* Wave Divider */}
            <div className="absolute top-0 left-0 w-full overflow-hidden">
                <svg className="relative block w-full h-16" viewBox="0 0 1200 120" preserveAspectRatio="none">
                    <path 
                        d="M321.39,56.44c58-10.79,114.16-30.13,172-41.86,82.39-16.72,168.19-17.73,250.45-.39C823.78,31,906.67,72,985.66,92.83c70.05,18.48,146.53,26.09,214.34,3V0H0V27.35A600.21,600.21,0,0,0,321.39,56.44Z" 
                        fill="currentColor" 
                        className="text-white/5"
                    ></path>
                </svg>
            </div>

            <div className="relative z-10 py-16 px-4 sm:px-6 lg:px-8">
                <div className="max-w-6xl mx-auto">

                    {/* Main Content Grid */}
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-12 mb-12">

                        {/* Logo & Message Section */}
                        <div className="lg:col-span-1 space-y-6">
                            {/* Logo */}
                            <div className="group flex items-center space-x-3">
                                <div className="relative">
                                    <div className="w-14 h-14 bg-gradient-to-br from-blue-500 via-purple-600 to-pink-500 rounded-2xl flex items-center justify-center transform group-hover:rotate-12 group-hover:scale-110 transition-all duration-500 shadow-2xl group-hover:shadow-purple-500/50">
                                        <Zap className="w-7 h-7 text-white" />
                                    </div>
                                    <div className="absolute -top-1 -right-1 w-4 h-4 bg-gradient-to-br from-yellow-400 to-orange-500 rounded-full opacity-80 group-hover:scale-125 group-hover:animate-spin transition-all duration-500">
                                        <Sparkles className="w-2 h-2 text-white absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2" />
                                    </div>
                                </div>
                                <div>
                                    <h3 className="text-2xl font-black bg-gradient-to-r from-blue-400 to-purple-400 bg-clip-text text-transparent">
                                        Forum Academy
                                    </h3>
                                    <p className="text-gray-400 text-sm">Innovate • Learn • Succeed</p>
                                </div>
                            </div>

                            {/* Message */}
                            <div className="bg-gradient-to-br from-slate-800/50 to-slate-900/50 backdrop-blur-xl rounded-2xl p-6 border border-white/10 hover:border-white/20 transition-all duration-300 group">
                                <p className="text-gray-300 leading-relaxed text-sm">
                                    {t('footer.description') || 'Empowering the next generation of tech innovators through cutting-edge education and hands-on experience in emerging technologies.'}
                                </p>
                                <div className="absolute inset-0 bg-gradient-to-br from-blue-500/0 to-purple-500/0 group-hover:from-blue-500/5 group-hover:to-purple-500/5 rounded-2xl transition-all duration-500 pointer-events-none"></div>
                            </div>

                            {/* Contact Info */}
                            <div className="space-y-4">
                                {[
                                    { icon: Mail, text: 'info@forumacademy.com', color: 'from-blue-500 to-cyan-500' },
                                    { icon: Phone, text: '+1 (555) 123-4567', color: 'from-green-500 to-emerald-500' },
                                    { icon: MapPin, text: '123 Tech Street, Silicon Valley, CA', color: 'from-purple-500 to-pink-500' }
                                ].map((contact, index) => {
                                    const IconComponent = contact.icon;
                                    return (
                                        <div key={index} className="group flex items-center space-x-4 text-gray-300 hover:text-white transition-all duration-300">
                                            <div className={`w-10 h-10 bg-gradient-to-br ${contact.color} rounded-xl flex items-center justify-center group-hover:scale-110 group-hover:rotate-6 transition-all duration-300 shadow-lg`}>
                                                <IconComponent className="w-5 h-5 text-white" />
                                            </div>
                                            <span className="text-sm group-hover:translate-x-1 transition-transform duration-300">{contact.text}</span>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>

                        {/* Navigation Links */}
                        <div className="lg:col-span-1">
                            <h4 className="text-xl font-bold text-white mb-8 flex items-center">
                                <div className="w-6 h-6 bg-gradient-to-br from-blue-500 to-purple-500 rounded-lg flex items-center justify-center mr-3">
                                    <div className="w-2 h-2 bg-white rounded-full"></div>
                                </div>
                                {t('footer.navigation') || 'Navigation'}
                            </h4>

                            <div className="grid grid-cols-1 gap-3">
                                {navigationLinks.map((link, index) => {
                                    const IconComponent = link.icon;
                                    return (
                                        <Link
                                            key={index}
                                            to={link.path}
                                            className="group flex items-center space-x-3 p-4 bg-gradient-to-r from-slate-800/30 to-slate-900/30 backdrop-blur-sm rounded-xl border border-white/10 hover:border-white/20 hover:from-slate-700/40 hover:to-slate-800/40 transition-all duration-300 hover:scale-[1.02] hover:shadow-lg"
                                        >
                                            <IconComponent className="w-5 h-5 text-gray-400 group-hover:text-white group-hover:scale-110 transition-all duration-300" />
                                            <span className="text-gray-300 group-hover:text-white group-hover:translate-x-1 transition-all duration-300 font-medium">
                                                {link.name}
                                            </span>
                                        </Link>
                                    );
                                })}
                            </div>
                        </div>

                        {/* Social Media Icons */}
                        <div className="lg:col-span-1">
                            <h4 className="text-xl font-bold text-white mb-8 flex items-center">
                                <div className="w-6 h-6 bg-gradient-to-br from-pink-500 to-purple-500 rounded-lg flex items-center justify-center mr-3">
                                    <Heart className="w-3 h-3 text-white" />
                                </div>
                                {t('footer.followUs') || 'Follow Us'}
                            </h4>

                            <div className="flex flex-wrap gap-4">
                                {socialLinks.map((social, index) => {
                                    const IconComponent = social.icon;
                                    return (
                                        <a
                                            key={index}
                                            href={social.url}
                                            className={`group w-14 h-14 bg-gradient-to-br from-slate-800/50 to-slate-900/50 backdrop-blur-sm rounded-2xl border border-white/10 flex items-center justify-center transition-all duration-300 hover:scale-110 hover:rotate-6 hover:shadow-xl ${social.color} hover:border-transparent`}
                                        >
                                            <IconComponent className="w-6 h-6 text-gray-400 group-hover:scale-125 transition-all duration-300" />
                                        </a>
                                    );
                                })}
                            </div>

                            {/* Additional Visual Element */}
                            <div className="mt-8 p-6 bg-gradient-to-br from-blue-500/10 to-purple-500/10 backdrop-blur-sm rounded-2xl border border-white/10">
                                <div className="flex items-center space-x-3 mb-3">
                                    <div className="w-8 h-8 bg-gradient-to-br from-yellow-400 to-orange-500 rounded-lg flex items-center justify-center">
                                        <Sparkles className="w-4 h-4 text-white" />
                                    </div>
                                    <h5 className="text-white font-bold">
                                        {t('footer.stayConnected') || 'Stay Connected'}
                                    </h5>
                                </div>
                                <p className="text-gray-300 text-sm">
                                    {t('footer.socialMessage') || 'Join our community and get the latest updates on tech trends and educational content.'}
                                </p>
                            </div>
                        </div>
                    </div>

                    {/* Bottom Section */}
                    <div className="border-t border-white/10 pt-8">
                        <div className="flex flex-col md:flex-row items-center justify-between space-y-4 md:space-y-0">
                            <div className="flex items-center text-gray-300 text-sm">
                                <span>{t('footer.copyright') || '© 2024 Forum Academy. All rights reserved.'}</span>
                                <Heart className="w-4 h-4 text-red-400 mx-3 animate-pulse" />
                                <span>{t('footer.madeWith') || 'Made with love for education'}</span>
                            </div>

                            <div className="flex items-center space-x-6">
                                <Link to="/privacy" className="text-gray-300 hover:text-white text-sm transition-all duration-300 hover:scale-105">
                                    {t('footer.privacy') || 'Privacy Policy'}
                                </Link>
                                <Link to="/terms" className="text-gray-300 hover:text-white text-sm transition-all duration-300 hover:scale-105">
                                    {t('footer.terms') || 'Terms of Service'}
                                </Link>

                                {/* Scroll to Top Button */}
                                <button
                                    onClick={scrollToTop}
                                    className="group w-12 h-12 bg-gradient-to-br from-blue-500 via-purple-600 to-pink-500 rounded-2xl flex items-center justify-center transition-all duration-500 hover:scale-125 hover:rotate-12 hover:shadow-2xl hover:shadow-purple-500/50 relative overflow-hidden"
                                >
                                    {/* Button Background Effect */}
                                    <div className="absolute inset-0 bg-gradient-to-r from-yellow-400/20 via-pink-400/20 to-cyan-400/20 opacity-0 group-hover:opacity-100 transition-opacity duration-500 animate-pulse"></div>

                                    {/* Sparkle Effects */}
                                    <div className="absolute top-1 left-1 w-1 h-1 bg-yellow-300 rounded-full opacity-0 group-hover:opacity-100 animate-ping transition-opacity duration-500 delay-100"></div>
                                    <div className="absolute bottom-1 right-1 w-1 h-1 bg-cyan-300 rounded-full opacity-0 group-hover:opacity-100 animate-pulse transition-opacity duration-500 delay-200"></div>

                                    {/* Icon */}
                                    <ChevronUp className="w-6 h-6 text-white group-hover:scale-110 group-hover:-translate-y-1 transition-all duration-300 relative z-10" />

                                    {/* Floating Ring */}
                                    <div className="absolute -top-1 -right-1 w-4 h-4 border-2 border-yellow-300 rounded-full opacity-0 group-hover:opacity-100 group-hover:animate-spin transition-all duration-500 delay-150"></div>
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </footer>
    );
};

export default Footer;
